import React from 'react';
import { Card } from './ui/card';
import { Button } from './ui/button';
import { Badge } from './ui/badge';
import { Github, ExternalLink, Bot, Mic, Briefcase, MessageSquare } from 'lucide-react';
import { motion } from 'framer-motion';

const Projects = () => {
  const projects = [
    {
      title: 'CortexAI – AI Powered Chatbot',
      description: 'Built a full-stack AI chatbot using Gemini API with Clerk authentication and MongoDB for chat history. Designed a responsive UI with Tailwind CSS and deployed on Vercel for global access.',
      icon: <MessageSquare size={40} />,
      tech: ['React', 'Next.js', 'MongoDB', 'Tailwind CSS', 'Gemini API', 'Clerk'],
      github: 'https://github.com/FAYAZKLU',
      demo: '#',
    },
    {
      title: 'Interview Buddy – AI Interview Mocker',
      description: 'Developed a mock interview app with AI-generated questions, voice recording, and webcam monitoring. Implemented feedback, ratings, and answer validation using Gemini API.',
      icon: <Bot size={40} />,
      tech: ['Next.js', 'React', 'Clerk', 'Drizzle ORM', 'Gemini API'],
      github: 'https://github.com/FAYAZKLU',
      demo: '#',
    },
    {
      title: 'Nexora - AI Virtual Assistant',
      description: 'Created a voice-controlled virtual assistant using Gemini and Web Speech APIs for real-time responses and voice synthesis. Designed an interactive and responsive UI.',
      icon: <Mic size={40} />,
      tech: ['React.js', 'Web Speech API', 'Gemini API', 'JavaScript'],
      github: 'https://github.com/FAYAZKLU',
      demo: '#',
    },
    {
      title: 'Automated Job Search Agent',
      description: 'Designed an n8n workflow that fetches job data from Sheets, filters LinkedIn jobs by resume score, and sends Telegram alerts for scores more than 60, automating job tracking.',
      icon: <Briefcase size={40} />,
      tech: ['n8n', 'Google Sheets API', 'Telegram Bot API', 'LinkedIn Scraper'],
      github: 'https://github.com/FAYAZKLU',
      demo: '#',
    },
  ];

  return (
    <motion.section
      id="projects"
      className="py-20 bg-cream"
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, amount: 0.2 }}
      transition={{ duration: 0.6, ease: 'easeOut' }}
    >
      <div className="container mx-auto px-6">
        <div className="max-w-6xl mx-auto">
          <div className="text-center mb-16">
            <h2 className="text-4xl md:text-5xl font-bold text-forest mb-4">Featured Projects</h2>
            <div className="w-20 h-1 bg-sage mx-auto mb-4"></div>
            <p className="text-forest/60 text-lg">Building innovative solutions with modern technologies</p>
          </div>

          <div className="grid md:grid-cols-2 gap-8">
            {projects.map((project, index) => (
              <Card key={index} className="bg-white border-sage/20 hover:border-sage transition-all duration-300 hover:shadow-2xl hover:-translate-y-2 group overflow-hidden">
                <div className="p-6">
                  <div className="mb-4 text-sage group-hover:text-forest transition-colors">{project.icon}</div>
                  <h3 className="text-2xl font-bold text-forest mb-3 group-hover:text-sage transition-colors">{project.title}</h3>
                  <p className="text-forest/70 mb-4 leading-relaxed">{project.description}</p>
                  <div className="flex flex-wrap gap-2 mb-6">
                    {project.tech.map((tech, techIndex) => (
                      <Badge key={techIndex} variant="outline" className="bg-cream border-sage/30 text-forest hover:bg-sage hover:text-white transition-colors">{tech}</Badge>
                    ))}
                  </div>
                  <div className="flex gap-3">
                    <Button variant="outline" size="sm" className="border-sage text-sage hover:bg-sage hover:text-white transition-all" onClick={() => window.open(project.github, '_blank')}>
                      <Github size={16} className="mr-2" />
                      Code
                    </Button>
                    {project.demo !== '#' && (
                      <Button size="sm" className="bg-forest hover:bg-forest/90 text-white transition-all" onClick={() => window.open(project.demo, '_blank')}>
                        <ExternalLink size={16} className="mr-2" />
                        Demo
                      </Button>
                    )}
                  </div>
                </div>
                <div className="h-1 bg-sage transform scale-x-0 group-hover:scale-x-100 transition-transform duration-300 origin-left"></div>
              </Card>
            ))}
          </div>
        </div>
      </div>
    </motion.section>
  );
};

export default Projects;
